var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어때요, 스승님. 제 말대로죠?","JPN":"どうですか、師匠。僕の言うとおりでしたね？","ENG":"What did I tell you, Master? I was right, huh?","TWN":"師父你看，我說的沒錯吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……운이 좋았다고 해 두지.","JPN":"……運が良かったということにしておこう。","ENG":"…You got lucky.","TWN":"……算你運氣好。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그나저나……. 루크레시아 님이라고 했던가요?","JPN":"ところで……ルクレシアさんとおっしゃいましたか？","ENG":"Anyway… Lady Lucrecia, was it?","TWN":"那個……你是叫露可蕾西亞嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"조금 억울하네요. 그런 식으로 이쪽에 책임을 떠넘기면 곤란합니다.","JPN":"少し気分が悪いですね。そうやってこちらに全責任を押し付けるのは困ります。","ENG":"Don't you think you're being a tad unfair? You can't just blame me for everything.","TWN":"你這樣說有點不公平喔，怎麼可以把責任推給我們呢？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"상호 합의를 먼저 어긴 것도, 제 시정 요구를 무시한 것도 그쪽일 텐데요?","JPN":"相互合意を先に破ったのも、是正要求を無視したのもそちらだと思いますが。","ENG":"You folks were the first to break our mutual agreement and disregard my request to take corrective action… weren't you?","TWN":"違反雙方協議，對於我提出的改正需求也不予理會的可是你們喔！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 일은 저도 유감이에요. 클라레스 전하께서 말씀을 거칠게 하신 건 사실이죠.","JPN":"その件は私も残念に思っています。クラレス殿下が少々言い過ぎたのは事実です。","ENG":"I too find that most regrettable. 'Tis true His Highness Prince Clareth spoke rather uncouthly with thee.","TWN":"對於那件事我深表遺憾，克拉雷斯殿下的發言確實有失身分。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 이유가 무엇이든, 저희의 뜻에 거스르는 것은 용납할 수 없습니다.","JPN":"しかし理由が何であれ、私たちの意思に逆らう行為は容認できません。","ENG":"But regardless of the reason, we shall not accept any defiance of our will.","TWN":"但無論理由是什麼，我們都絕對不接受抗命。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저런, 멋대로 남의 세계에 넘어와서는 원래 살던 사람들을 이방인이라고 부르다니. ","JPN":"おや、勝手に他人の世界に渡ってきて、元々住んでいた人たちのことを異邦人と呼ぶなんて。","ENG":"My, my. How can you call us outsiders when you're the ones squatting in our world? ","TWN":"哎呀～擅自侵犯別人的世界，還把原本住在那裡的人稱為外邦人，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"안타깝게도 정신 상태가 그리 온전치 못하신가 보네요.","JPN":"残念ながら精神状態がまともではないようですね。","ENG":"Sadly, it seems y'all are not quite right in the head.","TWN":"可憐喔～看來你病得不輕呢！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……뭐라고요?","JPN":"……なんですって？","ENG":"…What did you say?","TWN":"……你說什麼？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아, 너무 돌려 말해서 이해하시기 어려운 모양이군요. 쉽게 말씀드리죠.","JPN":"ああ、言い回しが難しくて理解できなかったようですね。シンプルに申し上げます。","ENG":"Oh, perhaps I've beat around the bush too much for you to understand. Let me put it bluntly, then.","TWN":"我講得太拐彎抹角你聽不懂嗎？那我就說白話文吧！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"헛소리 집어치우고 당장 주시윤 군을 풀어주지 않으면 당신은 이곳에서 죽는다는 뜻입니다.","JPN":"ふざけたことを抜かすのは辞めて今すぐアキヤマ君を解放しなければ、あなたはここで死ぬという意味です。","ENG":"If you don't shut up and release Joo Shiyoon at once, you're going to die here.","TWN":"少在那邊跟我廢話那麼多，現在就給我立刻放了周時雲，否則這裡就是你的葬身之地！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"존경하는 성녀님.","JPN":"尊敬する聖女様。","ENG":"Your venerable Saintess.","TWN":"尊敬的聖女大人，這樣有聽懂嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석, 못 보던 사이에 성격이 좀 변했군.","JPN":"あいつ、見ない間に性格がちょっと変わったな。","ENG":"He's changed a bit since I last saw him.","TWN":"看來那傢伙在這段時間個性又變了不少。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"꼭 그렇지만은 않습니다.","JPN":"別にそうでもありません。","ENG":"Not really.","TWN":"不是這樣的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님은 모르시겠지만 예전에도 어떤 면에서는 저 이상으로 과격한 면이 있었죠.","JPN":"師匠は知らないと思いますが、昔からある意味私以上に過激なところがありましたよ。","ENG":"You might not have known this, but he's always had that aggressive side to him in some ways.","TWN":"師父你可能不太清楚，但他從以前會因為某些事而失控，甚至比你剛看到的還要誇張。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"가, 감히 그 따위 말을……!","JPN":"よ、よくもそんなことを……！","ENG":"H-how dare you!","TWN":"大…大膽，竟然如此口無遮攔……！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너, 그 때 만났던 강령술사로군.","JPN":"お前、あの時に会った降霊術師だな。","ENG":"You're that necromancer from before.","TWN":"你是那時候的降靈術師對吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"주시윤을 납치해서 뭘 할 생각인지는 모르겠지만, 지금 내놓는다면 조용히 돌아가 주겠다.","JPN":"アキヤマを攫って何をするつもりか知らないが、今返すなら大人しく帰ってやる。","ENG":"I don't know what you plan to do with Shiyoon, but we'll leave quietly if you release him now.","TWN":"我不知道你們綁架周時雲要做什麼，但只要現在收手，我們就立刻乖乖回去。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나도 아직 사도들과 전면전을 벌일 생각은 없으니까.","JPN":"私もまだ使徒と全面戦争をするつもりはないからな。","ENG":"I have no desire to spark an all-out war with the Apostles at this time.","TWN":"我本來就沒有想要跟使徒正面交鋒的意思。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"설마 저번에 날 막아선 걸로 이번에도 날 상대할 수 있다고 생각하는 건 아니겠지?","JPN":"まさか、この前私を邪魔したことで、今回も私相手に戦えるとでも思っているのか？","ENG":"You don’t think you’d stand a chance against me just because of what happened last time?","TWN":"你該不會以為上次能攔住我，這次就能對付我吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너희들도 지금은 전력을 보존해야 할 때일 텐데.","JPN":"お前たちも今は戦力を温存すべき時だろう。","ENG":"You probably need to conserve your forces at this time.","TWN":"你們現在應該也要儲存戰力吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"싸움이라면 클리포트 게임이 시작된 후에 해도 충분해. 그러니…….","JPN":"戦いならクリフォトゲームが始まってからで十分だ。だから……","ENG":"There's plenty of fighting to do after the Qliphoth Game starts. So why don't you…","TWN":"等逆卡巴拉遊戲開始後再打也不遲，所以……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……뻔뻔하군요.","JPN":"……図々しいですね。","ENG":"…How shameless you are.","TWN":"……真是厚顏無恥！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지난번에도, 그리고 지금도. 저는 물론이고 이 도시마저 모르는 체 하시는군요.","JPN":"この前も、そして今も。私はもちろん、この都市のことまで知らないふりをするんですね。","ENG":"Just like last time… You feign complete ignorance of me and this city.","TWN":"你還真會裝傻，上次也這樣，這次也是，不管是對我還是這座城市…"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신에겐 죄책감이라는 것도 없습니까?","JPN":"あなたには罪悪感というものが無いのですか？","ENG":"Have you no sense of guilt?","TWN":"你知道愧疚兩個字怎麼寫嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하나의 세계가, 수많은 백성들이…….","JPN":"一つの世界が、幾多の民が……","ENG":"An entire world and its people…","TWN":"一個世界和無數的百姓……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 나의 구원자께서 당신 때문에 얼마나 오랫동안 고통 받아 왔는지, 정말 모르는 겁니까?","JPN":"そして、私の救世主様があなたのせいでどれだけ\\n長い間苦しんできたのか、本当にわからないのですか？","ENG":"…and my Savior suffered immensely for so long because of you. Have you no clue?","TWN":"還有我的救贖者大人，這麼長時間以來因為你而承受多少痛苦！你真的都不知道嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 주제에 고작 제자 한 명 구하려고 여기까지 걸어 들어오다니…….","JPN":"それなのに、たった一人の弟子のためにここまでくるとは……","ENG":"And now you venture in here just to save your apprentice…","TWN":"竟然還有臉踏進這裡說要救你的徒弟……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"발키리란 것들은 모두 당신처럼 뻔뻔한 건가요?","JPN":"ヴァルキリーというものは、みんなあなたのように厚かましい存在なのですか？","ENG":"Are all Valkyries as shameless as you?","TWN":"女武神都像你這麼不要臉嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아니면 당신에겐 이미 몇 번이나 겪어 온 일이라 아무런 감흥도 없어져 버린 겁니까?","JPN":"それとも、\\nあなたにとっては何度も経験したことにすぎないから、\\n何の感情も湧かなくなってしまったのですか？","ENG":"Or have you lost all interest now, having been through it so many times already?","TWN":"還是你已經經歷過這種事太多次，所以已經沒感覺了？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……오해가 있군.","JPN":"……誤解があるようだな。","ENG":"I think there's been a misunderstanding.","TWN":"……是不是有什麼誤會？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"난 정말 기억이 나질 않아. 너도, 이 도시도.","JPN":"私は本当に思い出せない。お前も、この都市も。","ENG":"I really don't remember any of it. Neither you nor this city.","TWN":"我真的對你或是這個城市真的完全沒印象。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"애초에 내 기억 대부분은 구속구에 의해 봉인되어 있는 상태다.","JPN":"そもそも、私の記憶のほとんどは拘束具で封印されている状態だ。","ENG":"Most of my memories are sealed by the fetters.","TWN":"我大部分的記憶一開始就因為拘束器的關係而封印著。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"뭐라고? 어떻게 그럴 수가……","JPN":"何ですって？　どうしてそんなこと……","ENG":"What? How can that be…?","TWN":"什麼？怎麼會……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 네가 무슨 말을 하는 건지는 대충 추측할 수 있지.","JPN":"しかし、お前が何を言っているのかは大体推測できる。","ENG":"But I can make a few guesses as to what you're talking about.","TWN":"但我大概可以猜到你在說什麼。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"지난 번 싸움으로 내 힘과 기억이 조금은 풀려 나왔으니까.","JPN":"前回の戦いで私の力と記憶が少し戻ったからだ。","ENG":"The last battle unlocked some of my powers and memories, after all.","TWN":"因為上次交手時有找回一些我的力量和記憶。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 그렇다면 나야말로 궁금하군. 네 세계를 멸망시킨 건 내가 아닐 텐데?","JPN":"だからこそ気になるな。お前の世界を滅ぼしたのは私ではないはずだが。","ENG":"But let me ask you this. I was not responsible for the death of your world, was I?","TWN":"不過我倒是覺得奇怪，害你的世界滅亡的應該不是我吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"왜 나에게 그런 증오를 쏟아내는 거지?","JPN":"なぜその憎しみを私に吐き出す？","ENG":"Why do you hate me so much?","TWN":"為什麼你要把怒氣發在我身上？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"몰라서 묻는 겁니까?! 당신이 우리 세계에 오지만 않았어도……!","JPN":"本気で聞いてるのですか！？　あなたさえ私たちの世界に来なかったら……！","ENG":"Have you really no clue?! If only you hadn't come to our world…!","TWN":"你是真不知道還假不知道？！要不是因為你來到我們的世界……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내가 오든 말든, 어차피 이터니움이 나타난 이상 그 세계의 멸망은 정해져 있던 거다.","JPN":"私が来ようが来まいが、エタニウムが出現した以上、その世界の滅亡は決まっていた。","ENG":"Regardless of my presence, any world where Eternium appears is marked for doom.","TWN":"不管我有沒有來，你的世界都會因為永恆之金的出現而滅亡，這是既定的事實。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"오히려 내가 있었기에 멸망이 조금 더 늦춰질 수 있었겠지. 그렇지 않나?","JPN":"むしろ私がいたからこそ、滅亡を少しでも遅らせることができただろう。違うか？","ENG":"If anything, my presence probably delayed the end. Wasn't that the case?","TWN":"反而是因為我的出現才能稍微延後滅亡的不是嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그건……","JPN":"それは……","ENG":"Well…","TWN":"那是……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네 세계를 지킬 의무가 있는 자는 따로 있었을 텐데?","JPN":"お前の世界を守る義務がある者は別にいたはずだが？","ENG":"And wasn't there someone else who was responsible for safeguarding your world?","TWN":"有義務要守護你的世界的應該另有其人，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"원망을 하려면 그에게 해라.","JPN":"恨むなら奴にしろ。","ENG":"He's the one to blame, if anything.","TWN":"你要發洩就找他吧！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"패배한 대적자에게.","JPN":"敗北した敵対者にな。","ENG":"The defeated Antagonist.","TWN":"去找那個打輸的敵對者！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"역시…… 당신한테 죄책감 따위를 기대한 제가 바보였어요.","JPN":"やはり……あなたに罪悪感なんて期待した私が愚かでした。","ENG":"Just as I feared… I'm a fool for hoping you'd bear any sense of guilt.","TWN":"果然是我好傻好天真……根本不該期待你會有一絲的愧疚。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신들은 그저 파멸을 몰고 다니는 역병 같은 존재일 뿐인데…….","JPN":"あなたたちはただ破滅を招く疫病のような存在にすぎないのに……","ENG":"You lot are nothing but a pestilence, who brings destruction wherever you go…","TWN":"你們不過就是帶來毀滅的瘟疫……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"정말 싸울 생각인가?","JPN":"本気で戦う気か？","ENG":"Are you really going to fight?","TWN":"你認真要打？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"말했듯이 너희들에게도 좋은 일이 아닐 텐데?","JPN":"さっき言ったとおり、お前たちにとっても利益はないぞ？","ENG":"Like I said, you guys have nothing to gain from this either.","TWN":"我醜話已經說前頭，打下去對你們沒好處的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"누가 그걸 정했죠?","JPN":"誰がそんなことを決めましたか？","ENG":"Says who?","TWN":"有沒有好處誰說了算？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저희는 더 이상 손해와 이득을 따지지 않습니다.","JPN":"私たちはもう損害も利益も問いません。","ENG":"We no longer count our profits and losses.","TWN":"我們早就不在乎什麼好不好處的，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"더 이상…… 잃어버릴 것 따위 없으니까.","JPN":"これ以上……失うものなんてないのですから。","ENG":"Because… we have nothing to lose anymore.","TWN":"因為……我們已經沒什麼可以失去的了。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……4종 침식체로군요.","JPN":"……第4種侵食体ですね。","ENG":"…Category 4's, huh.","TWN":"……原來是4類侵蝕體。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하급이긴 하지만 이터와 대형 타일런트, 그리고 다른 마왕의 죽은 하수인들까지.","JPN":"下級ではありますが、イーターと大型タイラント、そして他の魔王の手下まで。","ENG":"They're hardly top tier, but I see Eaters, Giant Tyrants, and even the long dead minions of other Demon Lords.","TWN":"雖然都是小角色，但裡面有暴食、大型暴君，還有其他魔王死掉的手下，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"언데드를 제법 많이 모아뒀군요.","JPN":"アンデッドをかなり集めていたんですね。","ENG":"She's got quite a collection of the zombies there.","TWN":"你收集不少活死人呢！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"성녀라고 하더니 폐지 줍는 취미 같은 게 있으신가 본데요.","JPN":"聖女と名乗っていましたが、古紙回収のような趣味がおありのようですね。面白いです。","ENG":"I didn't realize a Saintess would develop a penchant for collecting old trash.","TWN":"沒想到聖女的興趣竟然是撿破爛喔？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"어울리지 않게 말이 많아졌군, 나유빈.","JPN":"口数が多くなったな、イチノセ。","ENG":"It's not like you to be so chatty, Na Yubin.","TWN":"羅瑜斌，你話怎麼變這麼多？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"겁이 난다면 지금이라도 뒤로 빠져라. 내가 해결하지.","JPN":"怖いなら後ろに下がってろ。私がやる。","ENG":"If you're scared, it's not too late to fall back. I'll take care of this.","TWN":"是因為害怕嗎？怕的話就閃邊去，我來處理。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 그럴 리가요.","JPN":"ハハハ、まさか。","ENG":"Haha, of course not.","TWN":"哈哈～我怎麼會怕呢？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지원 부대가 없는 이상 아무리 스승님이라도 조금은 부담이 되겠죠.","JPN":"応援部隊がいない以上、いくら師匠でも少しは負担になるでしょう。","ENG":"Without any back up coming, even you'd break a sweat with this many C.O.s.","TWN":"在沒有支援部隊的情況下，只憑師父一個人還是會有點辛苦吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"예전처럼 제가 뒤를 맡겠습니다. 그 편이 스승님께도 익숙하시겠죠.","JPN":"昔のように後方は僕がひき受けます。その方が師匠も慣れているでしょうから。","ENG":"I've got your six, just like the good old days. I'm sure you'd be more comfortable with that.","TWN":"和以前一樣，我負責後面，這樣師父也好發揮吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……마음대로 해라.","JPN":"……勝手にしろ。","ENG":"…Suit yourself.","TWN":"……你開心就好。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"부활의 성녀로서, 축복 받은 아이들에게 명한다.","JPN":"復活の聖女として、祝福を受けた子へ命じる。","ENG":"As the Saintess of Resurrection, I command thee, my blessed children.","TWN":"我以復活聖女之名命令蒙福的子民們！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"가라! 가서 저 이방인들 또한 너희들과 같은 존재로 만들어라!","JPN":"行け！　あの異邦人たちをお前たちと同じ存在にしなさい！","ENG":"Go forth! Render unto the outsiders the same fate which befell you!","TWN":"去吧！去把那些外邦人變成你們的同類吧！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};